  apply Hready. exact Hin.
Qed.

Lemma env_fns_root_shadow_provenance_summary_evidence_global_env_with_local_bounds :
  forall env bounds,
    env_fns_root_shadow_provenance_summary_evidence env ->
    env_fns_root_shadow_provenance_summary_evidence
      (global_env_with_local_bounds env bounds).
Proof.
  intros env bounds Hevidence fname fdef Hlookup.
  change (lookup_fn fname (env_fns env) = Some fdef) in Hlookup.
  eapply callee_body_root_shadow_provenance_summary_global_env_with_local_bounds.
  exact (Hevidence fname fdef Hlookup).
Qed.


Lemma initial_store_for_fn_store_names_not_in_body_ctx :
  forall env fdef s x,
    initial_store_for_fn env fdef s ->
    ~ In x (ctx_names (fn_body_ctx fdef)) ->
    ~ In x (store_names s).
Proof.
  intros env fdef s x Hstore Hfresh Hin.
  pose proof (initial_store_for_fn_store_typed env fdef s Hstore)
    as Htyped.
  rewrite (store_typed_names env s (sctx_of_ctx (fn_body_ctx fdef))
    Htyped) in Hin.
  exact (Hfresh Hin).
Qed.


Lemma root_set_store_roots_named_stores_subset :
  forall roots roots_bound s,
    root_set_stores_subset roots roots_bound ->
    root_set_store_roots_named roots_bound s ->
    root_set_store_roots_named roots s.
Proof.
  unfold root_set_stores_subset, root_set_store_roots_named.
  intros roots roots_bound s Hsubset Hnamed z Hin.
  apply Hnamed. apply Hsubset. exact Hin.
Qed.

Lemma value_roots_within_store_named_exclude_root :
  forall roots v s x,
    value_roots_within roots v ->
    root_set_store_roots_named roots s ->
    ~ In x (store_names s) ->
    value_refs_exclude_root x v.
Proof.
  intros roots v s x Hroots Hnamed Hfresh.
  eapply value_roots_exclude_root.
  - exact Hroots.
  - eapply root_set_store_roots_named_excludes_name; eassumption.
Qed.


Lemma store_names_remove_absent :
  forall x s,
    ~ In x (store_names s) ->
    store_names (store_remove x s) = store_names s.
Proof.
  intros x s Hfresh.
  induction s as [| se rest IH]; simpl in *.
  - reflexivity.
  - destruct (ident_eqb x (se_name se)) eqn:Heq.
    + apply ident_eqb_eq in Heq. subst.
      exfalso. apply Hfresh. left. reflexivity.
    + simpl. f_equal.
      apply IH. intros Hin. apply Hfresh. right. exact Hin.
Qed.

Lemma bind_params_nil_values :
  forall ps s,
    bind_params ps [] s = s.
Proof.
  intros ps s. destruct ps; reflexivity.
Qed.

Lemma store_names_remove_params_bind_params_fresh :
  forall ps vs s s_body,
    params_fresh_in_store ps s ->
    store_names s_body = store_names (bind_params ps vs s) ->
    store_names (store_remove_params ps s_body) = store_names s.
Proof.
  induction ps as [| p ps IH]; intros vs s s_body Hfresh Hnames.
  - simpl in *. exact Hnames.
  - destruct vs as [| v vs].
    + simpl in Hnames. simpl.
      eapply (IH [] s (store_remove (param_name p) s_body)).
      * eapply params_fresh_in_store_tail. exact Hfresh.
      * rewrite bind_params_nil_values.
        rewrite store_names_remove_absent.
        -- exact Hnames.
        -- rewrite Hnames.
           eapply params_fresh_in_store_head. exact Hfresh.
    + simpl in Hnames. simpl.
      destruct s_body as [| se rest]; simpl in Hnames; try discriminate.
      inversion Hnames as [[Hhead Htail]].
      simpl. rewrite Hhead, ident_eqb_refl.
      eapply IH.
      * eapply params_fresh_in_store_tail. exact Hfresh.
      * exact Htail.
Qed.


