    initial_store_for_fn env f s ->
    eval env s (fn_body f) s' v ->
    value_has_type env s' v (fn_ret f).
Proof.
  intros env f s s' v Hunique Hsummary Hinitial Hin Hstore Heval.
  pose proof (lookup_fn_in_unique_by_name env
    (fn_name f) f Hin eq_refl Hunique) as Hlookup.
  eapply callee_body_root_shadow_captured_call_provenance_summary_big_step_safe_checked_initial_ready.
  - exact Hunique.
  - exact (Hsummary (fn_name f) f Hlookup).
  - exact Hinitial.
  - exact Hstore.
  - exact Heval.
Qed.


Lemma store_remove_mark_used_store_add_same :
  forall x T v s,
    store_remove x (store_mark_used x (store_add x T v s)) = s.
Proof.
  intros x T v s.
  unfold store_add. simpl. rewrite ident_eqb_refl. simpl.
  rewrite ident_eqb_refl. reflexivity.
Qed.

Lemma store_remove_hidden_after_params_mark_used :
  forall ps x T v s,
    ~ In x (ctx_names (params_ctx ps)) ->
    store_remove x
      (store_remove_params ps (store_mark_used x (store_add x T v s))) =
      store_remove_params ps s.
Proof.
  intros ps x T v s Hnotin.
  rewrite store_remove_params_store_remove_commute by exact Hnotin.
  rewrite store_remove_mark_used_store_add_same.
  reflexivity.
Qed.

Lemma store_lookup_store_mark_used_add_diff :
  forall x y T v s,
    x <> y ->
    store_lookup x (store_mark_used y (store_add y T v s)) =
    store_lookup x s.
Proof.
  intros x y T v s Hneq.
  unfold store_add. simpl. rewrite ident_eqb_refl. simpl.
  destruct (ident_eqb x y) eqn:Heq.
  - apply ident_eqb_eq in Heq. contradiction.
  - reflexivity.
Qed.

Lemma store_mark_used_store_mark_used_add_diff :
  forall x y T v s,
    x <> y ->
    store_mark_used x (store_mark_used y (store_add y T v s)) =
    store_mark_used y (store_add y T v (store_mark_used x s)).
Proof.
  intros x y T v s Hneq.
  unfold store_add. simpl. rewrite ident_eqb_refl. simpl.
  destruct (ident_eqb x y) eqn:Heq.
  - apply ident_eqb_eq in Heq. contradiction.
  - reflexivity.
Qed.

Lemma store_update_state_store_mark_used_add_diff :
