Lemma store_restore_path_store_mark_used_add_inv :
  forall x y path T v s s_hidden',
    x <> y ->
    store_restore_path x path
      (store_mark_used y (store_add y T v s)) = Some s_hidden' ->
    exists s',
      s_hidden' = store_mark_used y (store_add y T v s') /\
      store_restore_path x path s = Some s'.
Proof.
  intros x y path T v s s_hidden' Hneq Hrestore.
  unfold store_restore_path in *.
  eapply store_update_state_store_mark_used_add_inv; eassumption.
Qed.

Lemma store_consume_path_store_mark_used_add_inv :
  forall x y path T v s s_hidden',
    x <> y ->
    store_consume_path x path
      (store_mark_used y (store_add y T v s)) = Some s_hidden' ->
    exists s',
      s_hidden' = store_mark_used y (store_add y T v s') /\
      store_consume_path x path s = Some s'.
Proof.
  intros x y path T v s s_hidden' Hneq Hconsume.
  unfold store_consume_path in *.
  rewrite store_lookup_store_mark_used_add_diff in Hconsume by exact Hneq.
  destruct (store_lookup x s) as [se |] eqn:Hlookup; try discriminate.
  destruct (binding_available_b (se_state se) path) eqn:Havailable;
    try discriminate.
  eapply store_update_state_store_mark_used_add_inv; eassumption.
Qed.

Inductive store_consumed_hidden_frame_rel
    (x : ident) (T : Ty) (hidden : value) : store -> store -> Prop :=
  | SCHFR_Here : forall s,
      store_consumed_hidden_frame_rel x T hidden
        (store_mark_used x (store_add x T hidden s)) s
  | SCHFR_Keep : forall se s_with s_without,
      se_name se <> x ->
      store_consumed_hidden_frame_rel x T hidden s_with s_without ->
      store_consumed_hidden_frame_rel x T hidden
        (se :: s_with) (se :: s_without).

Lemma store_consumed_hidden_frame_rel_here :
  forall x T hidden s,
    store_consumed_hidden_frame_rel x T hidden
      (store_mark_used x (store_add x T hidden s)) s.
Proof.
  intros x T hidden s. constructor.
Qed.

Lemma store_consumed_hidden_frame_rel_remove_base :
  forall x T hidden s_with s_without,
    store_consumed_hidden_frame_rel x T hidden s_with s_without ->
    store_remove x s_with = s_without.
Proof.
  intros x T hidden s_with s_without Hrel.
  induction Hrel as [s | se s_with s_without Hsex _ IH].
  - apply store_remove_mark_used_store_add_same.
  - simpl. destruct (ident_eqb x (se_name se)) eqn:Heq.
    + apply ident_eqb_eq in Heq. subst x. contradiction.
    + rewrite IH. reflexivity.
Qed.

Lemma store_consumed_hidden_frame_rel_name_in :
  forall x T hidden s_with s_without,
    store_consumed_hidden_frame_rel x T hidden s_with s_without ->
    In x (store_names s_with).
Proof.
  intros x T hidden s_with s_without Hrel.
  induction Hrel as [s | se s_with s_without _ _ IH].
  - rewrite store_names_mark_used_readiness.
    unfold store_add. simpl. left. reflexivity.
  - simpl. right. exact IH.
Qed.


Lemma receiver_method_hidden_cleanup_matches_base_final_store :
  forall ps x T hidden s_method_hidden s_body_hidden s_body_base s_final,
    (store_hidden_frame_rel x T hidden s_body_hidden s_body_base \/
     store_consumed_hidden_frame_rel x T hidden s_body_hidden s_body_base) ->
    store_remove x s_method_hidden =
      store_remove_params ps (store_remove x s_body_hidden) ->
    s_final = store_remove_params ps s_body_base ->
    s_final = store_remove x s_method_hidden.
Proof.
  intros ps x T hidden s_method_hidden s_body_hidden s_body_base s_final
    Hrel Hhidden_cleanup Hraw_final.
  subst s_final. rewrite Hhidden_cleanup.
  destruct Hrel as [Hrel | Hrel].
  - rewrite (store_hidden_frame_rel_remove_base x T hidden
      s_body_hidden s_body_base Hrel). reflexivity.
  - rewrite (store_consumed_hidden_frame_rel_remove_base x T hidden
      s_body_hidden s_body_base Hrel). reflexivity.
Qed.

Lemma direct_receiver_method_hidden_cleanup_final_store_consumer :
  forall type_args fcall receiver_callee v_receiver
      s_method_hidden s_body_hidden s_body_base s_hidden s',
    s_hidden =
      store_remove receiver_method_hidden_receiver_name s_method_hidden ->
    s' =
      store_remove_params (apply_type_params type_args (fn_params fcall))
        s_body_base ->
    (store_hidden_frame_rel receiver_method_hidden_receiver_name
       (fn_ret receiver_callee) v_receiver s_body_hidden s_body_base \/
     store_consumed_hidden_frame_rel receiver_method_hidden_receiver_name
       (fn_ret receiver_callee) v_receiver s_body_hidden s_body_base) ->
    store_remove receiver_method_hidden_receiver_name s_method_hidden =
      store_remove_params (apply_type_params type_args (fn_params fcall))
        (store_remove receiver_method_hidden_receiver_name s_body_hidden) ->
    s' = s_hidden.
Proof.
  intros type_args fcall receiver_callee v_receiver s_method_hidden
    s_body_hidden s_body_base s_hidden s' Hhidden_final Hraw_final
    Hbody_rel Hhidden_cleanup.
  subst s_hidden.
  eapply receiver_method_hidden_cleanup_matches_base_final_store; eassumption.
Qed.

Lemma generic_receiver_method_hidden_cleanup_final_store_consumer :
  forall type_args receiver_type_args fcall receiver_callee v_receiver
      s_method_hidden s_body_hidden s_body_base s_hidden s',
    s_hidden =
      store_remove receiver_method_hidden_receiver_name s_method_hidden ->
    s' =
      store_remove_params (apply_type_params type_args (fn_params fcall))
        s_body_base ->
    (store_hidden_frame_rel receiver_method_hidden_receiver_name
       (subst_type_params_ty receiver_type_args (fn_ret receiver_callee))
       v_receiver s_body_hidden s_body_base \/
     store_consumed_hidden_frame_rel receiver_method_hidden_receiver_name
       (subst_type_params_ty receiver_type_args (fn_ret receiver_callee))
       v_receiver s_body_hidden s_body_base) ->
    store_remove receiver_method_hidden_receiver_name s_method_hidden =
      store_remove_params (apply_type_params type_args (fn_params fcall))
        (store_remove receiver_method_hidden_receiver_name s_body_hidden) ->
    s' = s_hidden.
Proof.
  intros type_args receiver_type_args fcall receiver_callee v_receiver
    s_method_hidden s_body_hidden s_body_base s_hidden s' Hhidden_final
    Hraw_final Hbody_rel Hhidden_cleanup.
  subst s_hidden.
  eapply receiver_method_hidden_cleanup_matches_base_final_store; eassumption.
Qed.


Lemma store_hidden_frame_rel_store_names_insert :
  forall x T hidden s_with s_without,
    store_hidden_frame_rel x T hidden s_with s_without ->
    exists prefix suffix,
      store_names s_with = prefix ++ x :: suffix /\
      store_names s_without = prefix ++ suffix.
Proof.
  intros x T hidden s_with s_without Hrel.
  induction Hrel as [s | se s_with s_without _ _ IH].
  - exists [], (store_names s). unfold store_add. simpl. split; reflexivity.
  - destruct IH as (prefix & suffix & Hwith & Hwithout).
    exists (se_name se :: prefix), suffix. simpl.
    rewrite Hwith. rewrite Hwithout. split; reflexivity.
Qed.

Lemma store_consumed_hidden_frame_rel_store_names_insert :
  forall x T hidden s_with s_without,
    store_consumed_hidden_frame_rel x T hidden s_with s_without ->
    exists prefix suffix,
      store_names s_with = prefix ++ x :: suffix /\
      store_names s_without = prefix ++ suffix.
Proof.
  intros x T hidden s_with s_without Hrel.
  induction Hrel as [s | se s_with s_without _ _ IH].
  - exists [], (store_names s). rewrite store_names_mark_used_readiness.
    unfold store_add. simpl. split; reflexivity.
  - destruct IH as (prefix & suffix & Hwith & Hwithout).
    exists (se_name se :: prefix), suffix. simpl.
    rewrite Hwith. rewrite Hwithout. split; reflexivity.
Qed.


Lemma store_consumed_hidden_frame_rel_lookup :
  forall x T hidden s_with s_without y,
    store_consumed_hidden_frame_rel x T hidden s_with s_without ->
    y <> x ->
    store_lookup y s_with = store_lookup y s_without.
Proof.
  intros x T hidden s_with s_without y Hrel Hyx.
  induction Hrel as [s | se s_with s_without Hsex _ IH].
  - apply store_lookup_store_mark_used_add_diff.
    intro Heq. apply Hyx. exact Heq.
  - simpl.
    destruct (ident_eqb y (se_name se)); try reflexivity.
    exact IH.
Qed.

Lemma store_consumed_hidden_frame_rel_mark_used :
  forall x T hidden s_with s_without y,
    store_consumed_hidden_frame_rel x T hidden s_with s_without ->
    y <> x ->
    store_consumed_hidden_frame_rel x T hidden
      (store_mark_used y s_with) (store_mark_used y s_without).
Proof.
  intros x T hidden s_with s_without y Hrel Hyx.
  induction Hrel as [s | se s_with s_without Hsex Hrel IH].
  - rewrite store_mark_used_store_mark_used_add_diff.
    + constructor.
    + intro Heq. apply Hyx. exact Heq.
  - simpl.
    destruct (ident_eqb y (se_name se)); constructor; assumption.
Qed.


Lemma store_consumed_hidden_frame_rel_update_state :
  forall x T hidden s_with s_without y f s_with',
    store_consumed_hidden_frame_rel x T hidden s_with s_without ->
    y <> x ->
    store_update_state y f s_with = Some s_with' ->
    exists s_without',
      store_update_state y f s_without = Some s_without' /\
      store_consumed_hidden_frame_rel x T hidden s_with' s_without'.
Proof.
  intros x T hidden s_with s_without y f s_with' Hrel.
  revert y f s_with'.
  induction Hrel as [s | se s_with s_without Hsex Hrel IH];
    intros y f s_with' Hyx Hupdate.
  - destruct (store_update_state_store_mark_used_add_inv
      y x f T hidden s s_with' Hyx Hupdate) as
      [s_without' [Hwith' Hwithout']].
    subst s_with'. exists s_without'. split; [exact Hwithout' | constructor].
  - simpl in Hupdate.
    destruct (ident_eqb y (se_name se)) eqn:Hy.
    + inversion Hupdate; subst s_with'.
      exists (MkStoreEntry (se_name se) (se_ty se) (se_val se)
        (f (se_state se)) :: s_without).
      split; [simpl; rewrite Hy; reflexivity |].
      constructor; assumption.
    + destruct (store_update_state y f s_with) as [tail' |] eqn:Htail;
        try discriminate.
      inversion Hupdate; subst s_with'.
      destruct (IH y f tail' Hyx Htail) as [tail0 [Htail0 Hrel0]].
      exists (se :: tail0). split.
      * simpl. rewrite Hy, Htail0. reflexivity.
      * constructor; assumption.
Qed.

Lemma store_hidden_frame_rel_update_state_lift :
  forall x T hidden s_with s_without y f s_without',
    store_hidden_frame_rel x T hidden s_with s_without ->
    y <> x ->
    store_update_state y f s_without = Some s_without' ->
    exists s_with',
      store_update_state y f s_with = Some s_with' /\
      store_hidden_frame_rel x T hidden s_with' s_without'.
Proof.
  intros x T hidden s_with s_without y f s_without' Hrel.
  revert y f s_without'.
  induction Hrel as [s | se s_with s_without Hsex Hrel IH];
    intros y f s_without' Hyx Hupdate.
  - unfold store_add. simpl.
    destruct (ident_eqb y x) eqn:Hy.
    + apply ident_eqb_eq in Hy. contradiction.
    + rewrite Hupdate.
      exists (store_add x T hidden s_without'). split; [reflexivity | constructor].
  - simpl in Hupdate.
    destruct (ident_eqb y (se_name se)) eqn:Hy.
    + inversion Hupdate; subst s_without'.
      exists (MkStoreEntry (se_name se) (se_ty se) (se_val se)
        (f (se_state se)) :: s_with).
      split.
      * simpl. rewrite Hy. reflexivity.
      * constructor; assumption.
    + destruct (store_update_state y f s_without) as [tail' |] eqn:Htail;
        try discriminate.
      inversion Hupdate; subst s_without'.
      destruct (IH y f tail' Hyx Htail) as [tail_with [Htail_with Hrel_tail]].
      exists (se :: tail_with). split.
      * simpl. rewrite Hy, Htail_with. reflexivity.
      * constructor; assumption.
Qed.

Lemma store_consumed_hidden_frame_rel_update_state_lift :
  forall x T hidden s_with s_without y f s_without',
    store_consumed_hidden_frame_rel x T hidden s_with s_without ->
    y <> x ->
    store_update_state y f s_without = Some s_without' ->
    exists s_with',
      store_update_state y f s_with = Some s_with' /\
      store_consumed_hidden_frame_rel x T hidden s_with' s_without'.
Proof.
  intros x T hidden s_with s_without y f s_without' Hrel.
  revert y f s_without'.
  induction Hrel as [s | se s_with s_without Hsex Hrel IH];
    intros y f s_without' Hyx Hupdate.
  - unfold store_add, store_mark_used. simpl.
    destruct (ident_eqb x x) eqn:Hxx; [| apply ident_eqb_neq in Hxx; contradiction].
    destruct (ident_eqb y x) eqn:Hy.
    + apply ident_eqb_eq in Hy. contradiction.
    + destruct (store_update_state y f s) as [tail' |] eqn:Htail;
        try discriminate.
      inversion Hupdate; subst tail'.
      exists (store_mark_used x (store_add x T hidden s_without')).
      split.
      * unfold store_add, store_mark_used. simpl.
        rewrite Hxx, Hy, Htail. reflexivity.
      * constructor.
  - simpl in Hupdate.
    destruct (ident_eqb y (se_name se)) eqn:Hy.
    + inversion Hupdate; subst s_without'.
      exists (MkStoreEntry (se_name se) (se_ty se) (se_val se)
        (f (se_state se)) :: s_with).
      split.
      * simpl. rewrite Hy. reflexivity.
      * constructor; assumption.
    + destruct (store_update_state y f s_without) as [tail' |] eqn:Htail;
        try discriminate.
      inversion Hupdate; subst s_without'.
      destruct (IH y f tail' Hyx Htail) as [tail_with [Htail_with Hrel_tail]].
      exists (se :: tail_with). split.
      * simpl. rewrite Hy, Htail_with. reflexivity.
      * constructor; assumption.
Qed.

Lemma store_hidden_frame_rel_update_val_lift :
  forall x T hidden s_with s_without y v_new s_without',
    store_hidden_frame_rel x T hidden s_with s_without ->
    y <> x ->
    store_update_val y v_new s_without = Some s_without' ->
    exists s_with',
      store_update_val y v_new s_with = Some s_with' /\
      store_hidden_frame_rel x T hidden s_with' s_without'.
Proof.
  intros x T hidden s_with s_without y v_new s_without' Hrel.
  revert y v_new s_without'.
  induction Hrel as [s | se s_with s_without Hsex Hrel IH];
    intros y v_new s_without' Hyx Hupdate.
  - unfold store_add. simpl.
    destruct (ident_eqb y x) eqn:Hy.
    + apply ident_eqb_eq in Hy. contradiction.
    + rewrite Hupdate.
      exists (store_add x T hidden s_without'). split; [reflexivity | constructor].
  - simpl in Hupdate.
    destruct (ident_eqb y (se_name se)) eqn:Hy.
    + inversion Hupdate; subst s_without'.
      exists (MkStoreEntry (se_name se) (se_ty se) v_new (se_state se) :: s_with).
      split.
      * simpl. rewrite Hy. reflexivity.
      * constructor; assumption.
    + destruct (store_update_val y v_new s_without) as [tail' |] eqn:Htail;
        try discriminate.
      inversion Hupdate; subst s_without'.
      destruct (IH y v_new tail' Hyx Htail) as [tail_with [Htail_with Hrel_tail]].
      exists (se :: tail_with). split.
      * simpl. rewrite Hy, Htail_with. reflexivity.
      * constructor; assumption.
Qed.

Lemma store_consumed_hidden_frame_rel_update_val_lift :
  forall x T hidden s_with s_without y v_new s_without',
    store_consumed_hidden_frame_rel x T hidden s_with s_without ->
    y <> x ->
    store_update_val y v_new s_without = Some s_without' ->
    exists s_with',
      store_update_val y v_new s_with = Some s_with' /\
      store_consumed_hidden_frame_rel x T hidden s_with' s_without'.
Proof.
  intros x T hidden s_with s_without y v_new s_without' Hrel.
  revert y v_new s_without'.
  induction Hrel as [s | se s_with s_without Hsex Hrel IH];
    intros y v_new s_without' Hyx Hupdate.
  - unfold store_add, store_mark_used. simpl.
    destruct (ident_eqb x x) eqn:Hxx; [| apply ident_eqb_neq in Hxx; contradiction].
    destruct (ident_eqb y x) eqn:Hy.
    + apply ident_eqb_eq in Hy. contradiction.
    + destruct (store_update_val y v_new s) as [tail' |] eqn:Htail;
        try discriminate.
      inversion Hupdate; subst tail'.
      exists (store_mark_used x (store_add x T hidden s_without')).
