Proof.
  intros env s raw_body method_name type_args receiver_name receiver_type_args
    receiver_args method_args target_synthetic_body hidden_synthetic_body
    T_receiver s' v Htarget Hhidden Heval Hreplay.
  destruct (generic_direct_call_receiver_method_eval_receiver_inv
    env s raw_body method_name type_args receiver_name receiver_type_args
    receiver_args method_args target_synthetic_body s' v Htarget Heval)
    as (s_receiver & v_receiver & _s_method_args & _vs_method &
