      as (_Hvalue & Hcases).
    destruct Hcases as [[_ Hstore] | [_ Hstore]];
      [rewrite Hstore; simpl; auto
      | rewrite Hstore; rewrite store_names_mark_used_readiness; simpl; auto]. }
  pose proof (proj1 (proj2 preservation_ready_eval_store_names_mutual)
    env s_var_hidden method_args s_args_hidden vs_method Heval_args Hready)
    as Hnames.
  assert (Hhidden_in_args :
    In receiver_method_hidden_receiver_name (store_names s_args_hidden)).
  { rewrite Hnames. exact Hhidden_in_var. }
  destruct (alpha_rename_fn_def_used_name_fresh_params_and_body_locals
    (store_names s_args_hidden) method_callee fcall used' type_args
    receiver_method_hidden_receiver_name Halpha Hhidden_in_args)
    as [Hnotin_params Hnotin_body_locals].
  exists s_var_hidden, s_args_hidden, s_body_hidden, method_callee, fcall,
    used', v_receiver_arg, vs_method, s_args_base.
  repeat split; try eassumption.
  rewrite Hremove_params.
  apply store_remove_params_store_remove_commute.
  exact Hnotin_params.
