          lia.
        * intros prefix0 suffix0 arg Hin.
          eapply IHn.
          pose proof (expr_size_callexpr_arg_lt callee args arg Hin).
          lia.
      + eapply alpha_rename_expr_receiver_method_hidden_receiver_call_expr_generic_insert.
        * intros rho0 prefix0 suffix0.
