Theorem hidden_frame_eval_lift_ready_mutual_rel_proven :
  forall env,
    hidden_frame_eval_lift_ready_mutual_rel env.
Proof.
  intro env.
  assert (Hmut :
    (forall s e s_base' v,
      eval env s e s_base' v ->
      forall x T hidden s_with,
        store_hidden_frame_rel x T hidden s_with s ->
        preservation_ready_expr e ->
        ~ In x (free_vars_expr e) ->
        ~ In x (expr_local_store_names e) ->
        store_refs_exclude_root x s ->
        exists s_with',
          eval env s_with e s_with' v /\
          store_hidden_frame_rel x T hidden s_with' s_base' /\
          store_refs_exclude_root x s_base' /\
          value_refs_exclude_root x v) /\
    (forall s args s_base' vs,
      eval_args env s args s_base' vs ->
      forall x T hidden s_with,
        store_hidden_frame_rel x T hidden s_with s ->
        preservation_ready_args args ->
        ~ In x (args_free_vars_ts args) ->
        ~ In x (args_local_store_names args) ->
        store_refs_exclude_root x s ->
        exists s_with',
          eval_args env s_with args s_with' vs /\
          store_hidden_frame_rel x T hidden s_with' s_base' /\
          store_refs_exclude_root x s_base' /\
          Forall (value_refs_exclude_root x) vs) /\
    (forall s fields defs s_base' values,
      eval_struct_fields env s fields defs s_base' values ->
      forall x T hidden s_with,
        store_hidden_frame_rel x T hidden s_with s ->
        preservation_ready_fields fields ->
        ~ In x (fields_free_vars_ts fields) ->
        ~ In x (fields_local_store_names fields) ->
        store_refs_exclude_root x s ->
        exists s_with',
          eval_struct_fields env s_with fields defs s_with' values /\
          store_hidden_frame_rel x T hidden s_with' s_base' /\
          store_refs_exclude_root x s_base' /\
          value_fields_refs_exclude_root x values)).
  { apply (hidden_frame_eval_eval_args_eval_struct_fields_ind env
      (fun s e s' v _ =>
        forall x T hidden s_with,
          store_hidden_frame_rel x T hidden s_with s ->
          preservation_ready_expr e ->
          ~ In x (free_vars_expr e) ->
          ~ In x (expr_local_store_names e) ->
          store_refs_exclude_root x s ->
          exists s_with',
            eval env s_with e s_with' v /\
            store_hidden_frame_rel x T hidden s_with' s' /\
            store_refs_exclude_root x s' /\
            value_refs_exclude_root x v)
      (fun s args s' vs _ =>
        forall x T hidden s_with,
          store_hidden_frame_rel x T hidden s_with s ->
          preservation_ready_args args ->
          ~ In x (args_free_vars_ts args) ->
          ~ In x (args_local_store_names args) ->
          store_refs_exclude_root x s ->
          exists s_with',
            eval_args env s_with args s_with' vs /\
            store_hidden_frame_rel x T hidden s_with' s' /\
            store_refs_exclude_root x s' /\
            Forall (value_refs_exclude_root x) vs)
      (fun s fields defs s' values _ =>
        forall x T hidden s_with,
          store_hidden_frame_rel x T hidden s_with s ->
          preservation_ready_fields fields ->
          ~ In x (fields_free_vars_ts fields) ->
          ~ In x (fields_local_store_names fields) ->
          store_refs_exclude_root x s ->
          exists s_with',
            eval_struct_fields env s_with fields defs s_with' values /\
            store_hidden_frame_rel x T hidden s_with' s' /\
            store_refs_exclude_root x s' /\
            value_fields_refs_exclude_root x values));
      try solve [intros; match goal with H : preservation_ready_expr _ |- _ => inversion H end].
    - intros s x T hidden s_with Hrel _ _ _ Hrefs.
      exists s_with. repeat split; try constructor; assumption.
    - intros s lit x T hidden s_with Hrel _ _ _ Hrefs.
      exists s_with. destruct lit; repeat split; try constructor; assumption.
    - intros s lit x T hidden s_with Hrel _ _ _ Hrefs.
      exists s_with. repeat split; try constructor; assumption.
    - intros s lit x T hidden s_with Hrel _ _ _ Hrefs.
      exists s_with. repeat split; try constructor; assumption.
    - intros s y se Hlookup Hconsume x T hidden s_with Hrel _ Hfree _ Hrefs.
      assert (Hyx : y <> x) by
        (intros Heq; apply Hfree; subst; simpl; left; reflexivity).
      assert (Hlookup_with : store_lookup y s_with = Some se).
      { rewrite (store_hidden_frame_rel_lookup x T hidden s_with s y Hrel Hyx).
        exact Hlookup. }
      exists s_with. repeat split; try assumption.
      + eapply Eval_Var_Copy; eassumption.
      + exact (store_refs_exclude_lookup_value x s y se Hrefs Hlookup).
    - intros s y se Hlookup Hconsume Hused x T hidden s_with Hrel _ Hfree _ Hrefs.
      assert (Hyx : y <> x) by
        (intros Heq; apply Hfree; subst; simpl; left; reflexivity).
      assert (Hlookup_with : store_lookup y s_with = Some se).
      { rewrite (store_hidden_frame_rel_lookup x T hidden s_with s y Hrel Hyx).
