      assert (Hlookup_with : store_lookup y s_with = Some old_e).
      { rewrite (store_hidden_frame_rel_lookup x T hidden s_with s y Hrel Hyx).
        exact Hlookup. }
      destruct (IH x T hidden s_with Hrel
        ltac:(match goal with H : preservation_ready_expr _ |- _ => exact H end)
        ltac:(simpl in Hfree; intros Hin; apply Hfree; right; exact Hin)
        ltac:(match goal with H : ~ In x (expr_local_store_names _) |- _ => exact H end)
        Hrefs) as [s1_with [Heval_with [Hrel1 [Hrefs1 Hvnew]]]].
