    - intros s s1 s2 y old_e e_new v_new Hlookup Heval_new IH Hupdate
        x T hidden s_with Hrel Hready Hfree Hlocal Hrefs.
      inversion Hready; subst.
      assert (Hyx : y <> x) by
        (intros Heq; apply Hfree; subst; simpl; left; reflexivity).
      assert (Hlookup_with : store_lookup y s_with = Some old_e).
      { rewrite (store_hidden_frame_rel_lookup x T hidden s_with s y Hrel Hyx).
