        (intros Heq; apply Hfree; subst; simpl; left; reflexivity).
      destruct (eval_place_hidden_frame_rel_lift s_with s p y path x T hidden
        Hrel Hplace_fresh Hrefs Heval_place) as [Hyx Hplace_with].
      assert (Hlookup_path_with : store_lookup_path y path s_with = Some old_v).
