        ltac:(match goal with H : preservation_ready_expr _ |- _ => exact H end)
        ltac:(simpl in Hfree; intros Hin; apply Hfree; right; exact Hin)
        ltac:(match goal with H : ~ In x (expr_local_store_names _) |- _ => exact H end)
