      + constructor.
    - intros s p y path rk Heval_place x T hidden s_with Hrel Hready Hfree _ Hrefs.
      inversion Hready; subst.
      assert (Hplace_fresh : place_name p <> x) by
        (intros Heq; apply Hfree; subst; simpl; left; reflexivity).
      destruct (eval_place_hidden_frame_rel_lift s_with s p y path x T hidden
        Hrel Hplace_fresh Hrefs Heval_place) as [Hyx Hplace_with].
      exists s_with. repeat split; try assumption.
      + eapply Eval_Borrow; eassumption.
      + constructor. apply ident_eqb_neq. intros Heq.
        apply Hyx. symmetry. exact Heq.
    - intros s fname fdef Hlookup Hcaps x T hidden s_with Hrel _ _ _ Hrefs.
      exists s_with. repeat split; try assumption.
      + eapply Eval_Fn; eassumption.
      + constructor. constructor.
    - intros s s1 s2 e1 e2 e3 v Heval_cond IHcond Heval_then IHthen
        x T hidden s_with Hrel Hready Hfree Hlocal Hrefs.
      inversion Hready; subst.
      assert (Hfree_cond : ~ In x (free_vars_expr e1)).
      { simpl in Hfree. intros Hin. apply Hfree. apply in_or_app. left. exact Hin. }
      assert (Hlocal_cond : ~ In x (expr_local_store_names e1)).
      { simpl in Hlocal. intros Hin. apply Hlocal. apply in_or_app. left. exact Hin. }
      destruct (IHcond x T hidden s_with Hrel
        ltac:(match goal with H : preservation_ready_expr e1 |- _ => exact H end)
        Hfree_cond Hlocal_cond Hrefs) as [s1_with [Heval_cond_with [Hrel1 [Hrefs1 _]]]].
      assert (Hfree_then : ~ In x (free_vars_expr e2)).
      { simpl in Hfree. intros Hin. apply Hfree. apply in_or_app. right.
        apply in_or_app. left. exact Hin. }
      assert (Hlocal_then : ~ In x (expr_local_store_names e2)).
      { simpl in Hlocal. intros Hin. apply Hlocal. apply in_or_app. right.
        apply in_or_app. left. exact Hin. }
      destruct (IHthen x T hidden s1_with Hrel1
        ltac:(match goal with H : preservation_ready_expr e2 |- _ => exact H end)
        Hfree_then Hlocal_then Hrefs1) as [s2_with [Heval_then_with [Hrel2 [Hrefs2 Hv]]]].
      exists s2_with. repeat split; try assumption.
      eapply Eval_If_True; eassumption.
    - intros s s1 s2 e1 e2 e3 v Heval_cond IHcond Heval_else IHelse
        x T hidden s_with Hrel Hready Hfree Hlocal Hrefs.
      inversion Hready; subst.
      assert (Hfree_cond : ~ In x (free_vars_expr e1)).
      { simpl in Hfree. intros Hin. apply Hfree. apply in_or_app. left. exact Hin. }
      assert (Hlocal_cond : ~ In x (expr_local_store_names e1)).
      { simpl in Hlocal. intros Hin. apply Hlocal. apply in_or_app. left. exact Hin. }
      destruct (IHcond x T hidden s_with Hrel
        ltac:(match goal with H : preservation_ready_expr e1 |- _ => exact H end)
        Hfree_cond Hlocal_cond Hrefs) as [s1_with [Heval_cond_with [Hrel1 [Hrefs1 _]]]].
      assert (Hfree_else : ~ In x (free_vars_expr e3)).
      { simpl in Hfree. intros Hin. apply Hfree. apply in_or_app. right.
        apply in_or_app. right. exact Hin. }
      assert (Hlocal_else : ~ In x (expr_local_store_names e3)).
      { simpl in Hlocal. intros Hin. apply Hlocal. apply in_or_app. right.
        apply in_or_app. right. exact Hin. }
      destruct (IHelse x T hidden s1_with Hrel1
        ltac:(match goal with H : preservation_ready_expr e3 |- _ => exact H end)
        Hfree_else Hlocal_else Hrefs1) as [s2_with [Heval_else_with [Hrel2 [Hrefs2 Hv]]]].
      exists s2_with. repeat split; try assumption.
      eapply Eval_If_False; eassumption.
    - intros s s_scrut s_branch s' scrut branches enum_name variant_name
        lts args values edef vdef binders ps e_branch v Heval_scrut IHscrut
        Hlookup_enum Hlookup_variant Hlookup_binders Hparams Hlen Hlookup
        Heval_branch IHbranch Hstore x T hidden s_with Hrel Hready Hfree Hlocal Hrefs.
      inversion Hready; subst.
      assert (Hfree_scrut : ~ In x (free_vars_expr scrut)).
      { simpl in Hfree. intros Hin. apply Hfree. apply in_or_app. left. exact Hin. }
      assert (Hlocal_scrut : ~ In x (expr_local_store_names scrut)).
      { simpl in Hlocal. intros Hin. apply Hlocal. apply in_or_app. left. exact Hin. }
      destruct (IHscrut x T hidden s_with Hrel
        ltac:(match goal with H : preservation_ready_expr scrut |- _ => exact H end)
        Hfree_scrut Hlocal_scrut Hrefs) as [s_scrut_with [Heval_scrut_with [Hrel_scrut [Hrefs_scrut Hvenum]]]].
      assert (Hready_branch : preservation_ready_expr e_branch)
        by (eapply lookup_match_branch_preservation_ready; eassumption).
      assert (Hfree_branches : ~ In x (match_branches_free_vars_ts branches)).
      { simpl in Hfree. intros Hin. apply Hfree. apply in_or_app. right. exact Hin. }
      assert (Hfree_branch : ~ In x (free_vars_expr e_branch))
        by (eapply match_branches_free_vars_ts_lookup_notin; eassumption).
      assert (Hlocal_branches : ~ In x (match_branches_local_store_names branches)).
      { simpl in Hlocal. intros Hin. apply Hlocal. apply in_or_app. right. exact Hin. }
      assert (Hlocal_branch : ~ In x (expr_local_store_names e_branch))
        by (eapply match_branches_local_store_names_lookup_notin; eassumption).
      assert (Hnotin_ps : ~ In x (ctx_names (params_ctx ps))).
      { rewrite (match_payload_params_opt_names_hfs binders lts args vdef ps Hparams).
        intros Hin. apply Hlocal_branches.
        eapply lookup_expr_branch_binders_local_store_names_in; eassumption. }
      destruct (IHbranch x T hidden (bind_params ps values s_scrut_with)
        (store_hidden_frame_rel_bind_params ps values x T hidden
          s_scrut_with s_scrut Hrel_scrut Hnotin_ps)
        Hready_branch Hfree_branch Hlocal_branch
        (bind_params_refs_exclude_root x ps values s_scrut
          ltac:(inversion Hvenum; subst; assumption) Hrefs_scrut)) as
        [s_branch_with [Heval_branch_with [Hrel_branch [Hrefs_branch Hv]]]].
      exists (store_remove_params ps s_branch_with). repeat split.
      + eapply Eval_MatchEnum.
        * exact Heval_scrut_with.
        * exact Hlookup_enum.
        * exact Hlookup_variant.
        * exact Hlookup_binders.
        * exact Hparams.
        * exact Hlen.
        * exact Hlookup.
        * exact Heval_branch_with.
        * reflexivity.
      + eapply store_remove_params_hidden_frame_rel; eassumption.
      + eapply store_remove_params_refs_exclude_root; eassumption.
      + assumption.
    - intros s x T hidden s_with Hrel _ _ _ Hrefs.
      exists s_with. repeat split; try constructor; assumption.
    - intros s s1 s2 e es v vs Heval_e IHe Heval_args IHargs
        x T hidden s_with Hrel Hready Hfree Hlocal Hrefs.
      inversion Hready; subst.
      destruct (args_free_vars_ts_cons_notin x e es Hfree) as [Hfree_e Hfree_es].
      destruct (args_local_store_names_cons_notin x e es Hlocal) as [Hlocal_e Hlocal_es].
      destruct (IHe x T hidden s_with Hrel
        ltac:(match goal with H : preservation_ready_expr e |- _ => exact H end)
        Hfree_e Hlocal_e Hrefs) as [s1_with [Heval_e_with [Hrel1 [Hrefs1 Hv]]]].
      destruct (IHargs x T hidden s1_with Hrel1
        ltac:(match goal with H : preservation_ready_args es |- _ => exact H end)
        Hfree_es Hlocal_es Hrefs1) as [s2_with [Heval_args_with [Hrel2 [Hrefs2 Hvs]]]].
      exists s2_with. repeat split; try assumption.
      + eapply EvalArgs_Cons; eassumption.
      + constructor; assumption.
    - intros s x T hidden s_with Hrel _ _ _ Hrefs.
      exists s_with. repeat split; try constructor; assumption.
    - intros s s1 s2 fields f rest e v values Hlookup Heval_e IHe
        Heval_fields IHfields x T hidden s_with Hrel Hready Hfree Hlocal Hrefs.
      assert (Hready_e : preservation_ready_expr e)
        by (eapply preservation_ready_fields_lookup; eassumption).
      assert (Hfree_e : ~ In x (free_vars_expr e))
        by (eapply fields_free_vars_ts_lookup_notin; eassumption).
      assert (Hlocal_e : ~ In x (expr_local_store_names e))
        by (eapply fields_local_store_names_lookup_notin; eassumption).
      destruct (IHe x T hidden s_with Hrel Hready_e Hfree_e Hlocal_e Hrefs)
        as [s1_with [Heval_e_with [Hrel1 [Hrefs1 Hv]]]].
      destruct (IHfields x T hidden s1_with Hrel1 Hready Hfree Hlocal Hrefs1)
        as [s2_with [Heval_fields_with [Hrel2 [Hrefs2 Hvalues]]]].
      exists s2_with. repeat split; try assumption.
      + eapply EvalStructFields_Cons; eassumption.
      + constructor; assumption.
  }
  unfold hidden_frame_eval_lift_ready_mutual_rel.
  destruct Hmut as [Heval [Hargs Hfields]].
  repeat split.
  - intros x T hidden s_with s_base e s_base' result Hrel Hready Hfree
      Hlocal Hrefs Heval_base.
    destruct (Heval s_base e s_base' result Heval_base x T hidden s_with
      Hrel Hready Hfree Hlocal Hrefs) as [s_with' [Heval_with [Hrel' _]]].
    exists s_with'. split; assumption.
  - intros x T hidden s_with s_base args s_base' vs Hrel Hready Hfree
      Hlocal Hrefs Heval_base.
    destruct (Hargs s_base args s_base' vs Heval_base x T hidden s_with
      Hrel Hready Hfree Hlocal Hrefs) as [s_with' [Heval_with [Hrel' _]]].
    exists s_with'. split; assumption.
  - intros x T hidden s_with s_base fields defs s_base' values Hrel Hready
      Hfree Hlocal Hrefs Heval_base.
    destruct (Hfields s_base fields defs s_base' values Heval_base x T hidden
      s_with Hrel Hready Hfree Hlocal Hrefs) as [s_with' [Heval_with [Hrel' _]]].
    exists s_with'. split; assumption.
Qed.

Theorem consumed_hidden_frame_eval_lift_ready_mutual_rel_proven :
  forall env,
    consumed_hidden_frame_eval_lift_ready_mutual_rel env.
Proof.
  intro env.
  assert (Hmut :
    (forall s e s_base' v,
      eval env s e s_base' v ->
      forall x T hidden s_with,
        store_consumed_hidden_frame_rel x T hidden s_with s ->
        preservation_ready_expr e ->
        ~ In x (free_vars_expr e) ->
        ~ In x (expr_local_store_names e) ->
        store_refs_exclude_root x s ->
        exists s_with',
          eval env s_with e s_with' v /\
          store_consumed_hidden_frame_rel x T hidden s_with' s_base' /\
          store_refs_exclude_root x s_base' /\
          value_refs_exclude_root x v) /\
    (forall s args s_base' vs,
      eval_args env s args s_base' vs ->
      forall x T hidden s_with,
        store_consumed_hidden_frame_rel x T hidden s_with s ->
        preservation_ready_args args ->
        ~ In x (args_free_vars_ts args) ->
        ~ In x (args_local_store_names args) ->
        store_refs_exclude_root x s ->
        exists s_with',
          eval_args env s_with args s_with' vs /\
          store_consumed_hidden_frame_rel x T hidden s_with' s_base' /\
          store_refs_exclude_root x s_base' /\
          Forall (value_refs_exclude_root x) vs) /\
    (forall s fields defs s_base' values,
      eval_struct_fields env s fields defs s_base' values ->
      forall x T hidden s_with,
        store_consumed_hidden_frame_rel x T hidden s_with s ->
        preservation_ready_fields fields ->
        ~ In x (fields_free_vars_ts fields) ->
        ~ In x (fields_local_store_names fields) ->
        store_refs_exclude_root x s ->
        exists s_with',
          eval_struct_fields env s_with fields defs s_with' values /\
          store_consumed_hidden_frame_rel x T hidden s_with' s_base' /\
          store_refs_exclude_root x s_base' /\
          value_fields_refs_exclude_root x values)).
  { apply (hidden_frame_eval_eval_args_eval_struct_fields_ind env
      (fun s e s' v _ =>
        forall x T hidden s_with,
          store_consumed_hidden_frame_rel x T hidden s_with s ->
          preservation_ready_expr e ->
          ~ In x (free_vars_expr e) ->
          ~ In x (expr_local_store_names e) ->
          store_refs_exclude_root x s ->
          exists s_with',
            eval env s_with e s_with' v /\
            store_consumed_hidden_frame_rel x T hidden s_with' s' /\
            store_refs_exclude_root x s' /\
            value_refs_exclude_root x v)
      (fun s args s' vs _ =>
        forall x T hidden s_with,
          store_consumed_hidden_frame_rel x T hidden s_with s ->
          preservation_ready_args args ->
          ~ In x (args_free_vars_ts args) ->
          ~ In x (args_local_store_names args) ->
          store_refs_exclude_root x s ->
          exists s_with',
            eval_args env s_with args s_with' vs /\
            store_consumed_hidden_frame_rel x T hidden s_with' s' /\
            store_refs_exclude_root x s' /\
            Forall (value_refs_exclude_root x) vs)
      (fun s fields defs s' values _ =>
        forall x T hidden s_with,
          store_consumed_hidden_frame_rel x T hidden s_with s ->
          preservation_ready_fields fields ->
          ~ In x (fields_free_vars_ts fields) ->
          ~ In x (fields_local_store_names fields) ->
          store_refs_exclude_root x s ->
          exists s_with',
            eval_struct_fields env s_with fields defs s_with' values /\
            store_consumed_hidden_frame_rel x T hidden s_with' s' /\
            store_refs_exclude_root x s' /\
            value_fields_refs_exclude_root x values));
      try solve [intros; match goal with H : preservation_ready_expr _ |- _ => inversion H end].
    - intros s x T hidden s_with Hrel _ _ _ Hrefs.
      exists s_with. repeat split; try constructor; assumption.
    - intros s lit x T hidden s_with Hrel _ _ _ Hrefs.
      exists s_with. destruct lit; repeat split; try constructor; assumption.
    - intros s lit x T hidden s_with Hrel _ _ _ Hrefs.
      exists s_with. repeat split; try constructor; assumption.
    - intros s lit x T hidden s_with Hrel _ _ _ Hrefs.
      exists s_with. repeat split; try constructor; assumption.
    - intros s y se Hlookup Hconsume x T hidden s_with Hrel _ Hfree _ Hrefs.
      assert (Hyx : y <> x) by
        (intros Heq; apply Hfree; subst; simpl; left; reflexivity).
      assert (Hlookup_with : store_lookup y s_with = Some se).
      { rewrite (store_consumed_hidden_frame_rel_lookup x T hidden s_with s y Hrel Hyx).
        exact Hlookup. }
      exists s_with. repeat split; try assumption.
      + eapply Eval_Var_Copy; eassumption.
      + exact (store_refs_exclude_lookup_value x s y se Hrefs Hlookup).
    - intros s y se Hlookup Hconsume Hused x T hidden s_with Hrel _ Hfree _ Hrefs.
      assert (Hyx : y <> x) by
        (intros Heq; apply Hfree; subst; simpl; left; reflexivity).
      assert (Hlookup_with : store_lookup y s_with = Some se).
      { rewrite (store_consumed_hidden_frame_rel_lookup x T hidden s_with s y Hrel Hyx).
        exact Hlookup. }
      exists (store_mark_used y s_with). repeat split.
      + eapply Eval_Var_Consume; eassumption.
      + eapply store_consumed_hidden_frame_rel_mark_used; eassumption.
      + apply store_mark_used_refs_exclude_root. exact Hrefs.
      + exact (store_refs_exclude_lookup_value x s y se Hrefs Hlookup).
    - intros s p y path se Ty v Heval_place Hlookup Havail Hty Hneeds Hvalue
        x T hidden s_with Hrel Hready Hfree _ Hrefs.
      inversion Hready; subst; clear Hready.
      assert (Hplace_fresh : place_name p <> x) by
        (intros Heq; apply Hfree; subst; simpl; left; reflexivity).
      destruct (eval_place_consumed_hidden_frame_rel_lift s_with s p y path x T hidden
        Hrel Hplace_fresh Hrefs Heval_place) as [Hyx Hplace_with].
      assert (Hlookup_with : store_lookup y s_with = Some se).
      { rewrite (store_consumed_hidden_frame_rel_lookup x T hidden s_with s y Hrel Hyx).
        exact Hlookup. }
      exists s_with. repeat split; try assumption.
      + eapply Eval_Place_Copy; eassumption.
      + eapply value_refs_exclude_lookup_path.
        * exact (store_refs_exclude_lookup_value x s y se Hrefs Hlookup).
        * exact Hvalue.
    - intros s s' p y path se Ty v Heval_place Hlookup Havail Hty Hneeds
        Hvalue Hconsume x T hidden s_with Hrel Hready Hfree _ Hrefs.
      inversion Hready; subst; clear Hready.
      assert (Hplace_fresh : place_name p <> x) by
        (intros Heq; apply Hfree; subst; simpl; left; reflexivity).
      destruct (eval_place_consumed_hidden_frame_rel_lift s_with s p y path x T hidden
        Hrel Hplace_fresh Hrefs Heval_place) as [Hyx Hplace_with].
      assert (Hlookup_with : store_lookup y s_with = Some se).
      { rewrite (store_consumed_hidden_frame_rel_lookup x T hidden s_with s y Hrel Hyx).
        exact Hlookup. }
      destruct (store_consumed_hidden_frame_rel_consume_path_lift x T hidden s_with s
        y path s' Hrel Hyx Hconsume) as [s_with' [Hconsume_with Hrel']].
      exists s_with'. repeat split; try assumption.
      + eapply Eval_Place_Consume; eassumption.
      + eapply store_consume_path_refs_exclude_root; eassumption.
      + eapply value_refs_exclude_lookup_path.
        * exact (store_refs_exclude_lookup_value x s y se Hrefs Hlookup).
        * exact Hvalue.
    - intros s s' name lts args fields values sdef Hlookup Heval_fields IH
        x T hidden s_with Hrel Hready Hfree Hlocal Hrefs.
      inversion Hready; subst.
      destruct (IH x T hidden s_with Hrel
        ltac:(match goal with H : preservation_ready_fields fields |- _ => exact H end)
        Hfree Hlocal Hrefs) as [s_with' [Heval_with [Hrel' [Hrefs' Hvalues]]]].
      exists s_with'. repeat split; try assumption.
      + eapply Eval_Struct; eassumption.
      + constructor. exact Hvalues.
    - intros s s' enum_name variant_name lts variant_lts args payloads values
        edef vdef Hlookup Hvariant Heval_args IH x T hidden s_with Hrel Hready
        Hfree Hlocal Hrefs.
      inversion Hready; subst.
      destruct (IH x T hidden s_with Hrel
        ltac:(match goal with H : preservation_ready_args payloads |- _ => exact H end)
        Hfree Hlocal Hrefs) as [s_with' [Heval_with [Hrel' [Hrefs' Hvalues]]]].
      exists s_with'. repeat split; try assumption.
      + eapply Eval_Enum; eassumption.
      + constructor. exact Hvalues.
    - intros s s' e v Heval IH x T hidden s_with Hrel Hready Hfree Hlocal Hrefs.
      inversion Hready; subst.
      destruct (IH x T hidden s_with Hrel
        ltac:(match goal with H : preservation_ready_expr e |- _ => exact H end)
        Hfree Hlocal Hrefs) as [s_with' [Heval_with [Hrel' [Hrefs' _]]]].
      exists s_with'. repeat split; try assumption.
      + eapply Eval_Drop. exact Heval_with.
      + constructor.
    - intros s s1 s2 s3 y old_e e_new v_new Hlookup Heval_new IH
        Hupdate Hrestore x T hidden s_with Hrel Hready Hfree Hlocal Hrefs.
      inversion Hready; subst.
      assert (Hyx : y <> x) by
        (intros Heq; apply Hfree; subst; simpl; left; reflexivity).
      assert (Hlookup_with : store_lookup y s_with = Some old_e).
      { rewrite (store_consumed_hidden_frame_rel_lookup x T hidden s_with s y Hrel Hyx).
        exact Hlookup. }
      destruct (IH x T hidden s_with Hrel
        ltac:(match goal with H : preservation_ready_expr _ |- _ => exact H end)
        ltac:(simpl in Hfree; intros Hin; apply Hfree; right; exact Hin)
        ltac:(match goal with H : ~ In x (expr_local_store_names _) |- _ => exact H end)
        Hrefs) as [s1_with [Heval_with [Hrel1 [Hrefs1 Hvnew]]]].
      destruct (store_consumed_hidden_frame_rel_update_val_lift x T hidden s1_with s1
        y v_new s2 Hrel1 Hyx Hupdate) as [s2_with [Hupdate_with Hrel2]].
      destruct (store_consumed_hidden_frame_rel_restore_path_lift x T hidden s2_with s2
        y [] s3 Hrel2 Hyx Hrestore) as [s3_with [Hrestore_with Hrel3]].
      exists s3_with. repeat split; try assumption.
      + eapply Eval_Replace; eassumption.
      + eapply store_restore_path_refs_exclude_root.
        * eapply store_update_val_refs_exclude_root; eassumption.
        * exact Hrestore.
      + exact (store_refs_exclude_lookup_value x s y old_e Hrefs Hlookup).
    - intros s s1 s2 y old_e e_new v_new Hlookup Heval_new IH Hupdate
        x T hidden s_with Hrel Hready Hfree Hlocal Hrefs.
      inversion Hready; subst.
      assert (Hyx : y <> x) by
        (intros Heq; apply Hfree; subst; simpl; left; reflexivity).
      assert (Hlookup_with : store_lookup y s_with = Some old_e).
      { rewrite (store_consumed_hidden_frame_rel_lookup x T hidden s_with s y Hrel Hyx).
        exact Hlookup. }
      destruct (IH x T hidden s_with Hrel
        ltac:(match goal with H : preservation_ready_expr _ |- _ => exact H end)
        ltac:(simpl in Hfree; intros Hin; apply Hfree; right; exact Hin)
        ltac:(match goal with H : ~ In x (expr_local_store_names _) |- _ => exact H end)
        Hrefs) as [s1_with [Heval_with [Hrel1 [Hrefs1 Hvnew]]]].
      destruct (store_consumed_hidden_frame_rel_update_val_lift x T hidden s1_with s1
        y v_new s2 Hrel1 Hyx Hupdate) as [s2_with [Hupdate_with Hrel2]].
      exists s2_with. repeat split; try assumption.
      + eapply Eval_Assign; eassumption.
      + eapply store_update_val_refs_exclude_root; eassumption.
      + constructor.
    - intros s s1 s2 s3 p y path old_v e_new v_new Heval_place Hlookup_path
        Heval_new IH Hupdate Hrestore x T hidden s_with Hrel Hready Hfree
        Hlocal Hrefs.
      inversion Hready; subst.
      assert (Hplace_fresh : place_name p <> x) by
        (intros Heq; apply Hfree; subst; simpl; left; reflexivity).
      destruct (eval_place_consumed_hidden_frame_rel_lift s_with s p y path x T hidden
        Hrel Hplace_fresh Hrefs Heval_place) as [Hyx Hplace_with].
      assert (Hlookup_path_with : store_lookup_path y path s_with = Some old_v).
      { unfold store_lookup_path in *.
        rewrite (store_consumed_hidden_frame_rel_lookup x T hidden s_with s y Hrel Hyx).
        exact Hlookup_path. }
      destruct (IH x T hidden s_with Hrel
        ltac:(match goal with H : preservation_ready_expr _ |- _ => exact H end)
        ltac:(simpl in Hfree; intros Hin; apply Hfree; right; exact Hin)
        ltac:(match goal with H : ~ In x (expr_local_store_names _) |- _ => exact H end)
        Hrefs) as [s1_with [Heval_with [Hrel1 [Hrefs1 Hvnew]]]].
      destruct (store_consumed_hidden_frame_rel_update_path_lift x T hidden s1_with s1
        y path v_new s2 Hrel1 Hyx Hupdate) as [s2_with [Hupdate_with Hrel2]].
      destruct (store_consumed_hidden_frame_rel_restore_path_lift x T hidden s2_with s2
        y path s3 Hrel2 Hyx Hrestore) as [s3_with [Hrestore_with Hrel3]].
      exists s3_with. repeat split; try assumption.
      + eapply Eval_Replace_Place; eassumption.
      + eapply store_restore_path_refs_exclude_root.
        * eapply store_update_path_refs_exclude_root; eassumption.
        * exact Hrestore.
      + unfold store_lookup_path in Hlookup_path.
        destruct (store_lookup y s) as [se |] eqn:Hlookup_base;
          simpl in Hlookup_path; try discriminate.
        pose proof (store_refs_exclude_lookup_value x s y se Hrefs Hlookup_base)
          as Hse_refs.
        exact (value_refs_exclude_lookup_path x (se_val se) path old_v
          Hse_refs Hlookup_path).
    - intros s s1 s2 p y path e_new v_new Heval_place Heval_new IH Hupdate
        x T hidden s_with Hrel Hready Hfree Hlocal Hrefs.
      inversion Hready; subst.
      assert (Hplace_fresh : place_name p <> x) by
        (intros Heq; apply Hfree; subst; simpl; left; reflexivity).
      destruct (eval_place_consumed_hidden_frame_rel_lift s_with s p y path x T hidden
        Hrel Hplace_fresh Hrefs Heval_place) as [Hyx Hplace_with].
      destruct (IH x T hidden s_with Hrel
        ltac:(match goal with H : preservation_ready_expr _ |- _ => exact H end)
        ltac:(simpl in Hfree; intros Hin; apply Hfree; right; exact Hin)
        ltac:(match goal with H : ~ In x (expr_local_store_names _) |- _ => exact H end)
        Hrefs) as [s1_with [Heval_with [Hrel1 [Hrefs1 Hvnew]]]].
      destruct (store_consumed_hidden_frame_rel_update_path_lift x T hidden s1_with s1
        y path v_new s2 Hrel1 Hyx Hupdate) as [s2_with [Hupdate_with Hrel2]].
      exists s2_with. repeat split; try assumption.
      + eapply Eval_Assign_Place; eassumption.
      + eapply store_update_path_refs_exclude_root; eassumption.
      + constructor.
    - intros s p y path rk Heval_place x T hidden s_with Hrel Hready Hfree _ Hrefs.
      inversion Hready; subst.
      assert (Hplace_fresh : place_name p <> x) by
        (intros Heq; apply Hfree; subst; simpl; left; reflexivity).
      destruct (eval_place_consumed_hidden_frame_rel_lift s_with s p y path x T hidden
        Hrel Hplace_fresh Hrefs Heval_place) as [Hyx Hplace_with].
      exists s_with. repeat split; try assumption.
      + eapply Eval_Borrow; eassumption.
      + constructor. apply ident_eqb_neq. intros Heq.
        apply Hyx. symmetry. exact Heq.
    - intros s fname fdef Hlookup Hcaps x T hidden s_with Hrel _ _ _ Hrefs.
      exists s_with. repeat split; try assumption.
      + eapply Eval_Fn; eassumption.
      + constructor. constructor.
    - intros s s1 s2 e1 e2 e3 v Heval_cond IHcond Heval_then IHthen
        x T hidden s_with Hrel Hready Hfree Hlocal Hrefs.
      inversion Hready; subst.
      assert (Hfree_cond : ~ In x (free_vars_expr e1)).
      { simpl in Hfree. intros Hin. apply Hfree. apply in_or_app. left. exact Hin. }
      assert (Hlocal_cond : ~ In x (expr_local_store_names e1)).
      { simpl in Hlocal. intros Hin. apply Hlocal. apply in_or_app. left. exact Hin. }
      destruct (IHcond x T hidden s_with Hrel
        ltac:(match goal with H : preservation_ready_expr e1 |- _ => exact H end)
        Hfree_cond Hlocal_cond Hrefs) as [s1_with [Heval_cond_with [Hrel1 [Hrefs1 _]]]].
      assert (Hfree_then : ~ In x (free_vars_expr e2)).
      { simpl in Hfree. intros Hin. apply Hfree. apply in_or_app. right.
        apply in_or_app. left. exact Hin. }
      assert (Hlocal_then : ~ In x (expr_local_store_names e2)).
      { simpl in Hlocal. intros Hin. apply Hlocal. apply in_or_app. right.
        apply in_or_app. left. exact Hin. }
      destruct (IHthen x T hidden s1_with Hrel1
        ltac:(match goal with H : preservation_ready_expr e2 |- _ => exact H end)
        Hfree_then Hlocal_then Hrefs1) as [s2_with [Heval_then_with [Hrel2 [Hrefs2 Hv]]]].
      exists s2_with. repeat split; try assumption.
      eapply Eval_If_True; eassumption.
    - intros s s1 s2 e1 e2 e3 v Heval_cond IHcond Heval_else IHelse
        x T hidden s_with Hrel Hready Hfree Hlocal Hrefs.
      inversion Hready; subst.
      assert (Hfree_cond : ~ In x (free_vars_expr e1)).
      { simpl in Hfree. intros Hin. apply Hfree. apply in_or_app. left. exact Hin. }
      assert (Hlocal_cond : ~ In x (expr_local_store_names e1)).
      { simpl in Hlocal. intros Hin. apply Hlocal. apply in_or_app. left. exact Hin. }
      destruct (IHcond x T hidden s_with Hrel
        ltac:(match goal with H : preservation_ready_expr e1 |- _ => exact H end)
        Hfree_cond Hlocal_cond Hrefs) as [s1_with [Heval_cond_with [Hrel1 [Hrefs1 _]]]].
      assert (Hfree_else : ~ In x (free_vars_expr e3)).
      { simpl in Hfree. intros Hin. apply Hfree. apply in_or_app. right.
        apply in_or_app. right. exact Hin. }
      assert (Hlocal_else : ~ In x (expr_local_store_names e3)).
      { simpl in Hlocal. intros Hin. apply Hlocal. apply in_or_app. right.
        apply in_or_app. right. exact Hin. }
      destruct (IHelse x T hidden s1_with Hrel1
        ltac:(match goal with H : preservation_ready_expr e3 |- _ => exact H end)
        Hfree_else Hlocal_else Hrefs1) as [s2_with [Heval_else_with [Hrel2 [Hrefs2 Hv]]]].
      exists s2_with. repeat split; try assumption.
      eapply Eval_If_False; eassumption.
    - intros s s_scrut s_branch s' scrut branches enum_name variant_name
        lts args values edef vdef binders ps e_branch v Heval_scrut IHscrut
        Hlookup_enum Hlookup_variant Hlookup_binders Hparams Hlen Hlookup
        Heval_branch IHbranch Hstore x T hidden s_with Hrel Hready Hfree Hlocal Hrefs.
      inversion Hready; subst.
      assert (Hfree_scrut : ~ In x (free_vars_expr scrut)).
      { simpl in Hfree. intros Hin. apply Hfree. apply in_or_app. left. exact Hin. }
      assert (Hlocal_scrut : ~ In x (expr_local_store_names scrut)).
      { simpl in Hlocal. intros Hin. apply Hlocal. apply in_or_app. left. exact Hin. }
      destruct (IHscrut x T hidden s_with Hrel
        ltac:(match goal with H : preservation_ready_expr scrut |- _ => exact H end)
        Hfree_scrut Hlocal_scrut Hrefs) as [s_scrut_with [Heval_scrut_with [Hrel_scrut [Hrefs_scrut Hvenum]]]].
      assert (Hready_branch : preservation_ready_expr e_branch)
        by (eapply lookup_match_branch_preservation_ready; eassumption).
      assert (Hfree_branches : ~ In x (match_branches_free_vars_ts branches)).
      { simpl in Hfree. intros Hin. apply Hfree. apply in_or_app. right. exact Hin. }
      assert (Hfree_branch : ~ In x (free_vars_expr e_branch))
        by (eapply match_branches_free_vars_ts_lookup_notin; eassumption).
      assert (Hlocal_branches : ~ In x (match_branches_local_store_names branches)).
      { simpl in Hlocal. intros Hin. apply Hlocal. apply in_or_app. right. exact Hin. }
      assert (Hlocal_branch : ~ In x (expr_local_store_names e_branch))
        by (eapply match_branches_local_store_names_lookup_notin; eassumption).
      assert (Hnotin_ps : ~ In x (ctx_names (params_ctx ps))).
      { rewrite (match_payload_params_opt_names_hfs binders lts args vdef ps Hparams).
        intros Hin. apply Hlocal_branches.
        eapply lookup_expr_branch_binders_local_store_names_in; eassumption. }
      destruct (IHbranch x T hidden (bind_params ps values s_scrut_with)
        (store_consumed_hidden_frame_rel_bind_params_lift ps values x T hidden
          s_scrut_with s_scrut Hrel_scrut Hnotin_ps)
        Hready_branch Hfree_branch Hlocal_branch
        (bind_params_refs_exclude_root x ps values s_scrut
          ltac:(inversion Hvenum; subst; assumption) Hrefs_scrut)) as
        [s_branch_with [Heval_branch_with [Hrel_branch [Hrefs_branch Hv]]]].
      exists (store_remove_params ps s_branch_with). repeat split.
      + eapply Eval_MatchEnum.
        * exact Heval_scrut_with.
        * exact Hlookup_enum.
        * exact Hlookup_variant.
        * exact Hlookup_binders.
        * exact Hparams.
        * exact Hlen.
        * exact Hlookup.
        * exact Heval_branch_with.
        * reflexivity.
      + eapply store_consumed_hidden_frame_rel_remove_params_lift; eassumption.
      + eapply store_remove_params_refs_exclude_root; eassumption.
      + assumption.
    - intros s x T hidden s_with Hrel _ _ _ Hrefs.
      exists s_with. repeat split; try constructor; assumption.
    - intros s s1 s2 e es v vs Heval_e IHe Heval_args IHargs
        x T hidden s_with Hrel Hready Hfree Hlocal Hrefs.
      inversion Hready; subst.
      destruct (args_free_vars_ts_cons_notin x e es Hfree) as [Hfree_e Hfree_es].
      destruct (args_local_store_names_cons_notin x e es Hlocal) as [Hlocal_e Hlocal_es].
      destruct (IHe x T hidden s_with Hrel
        ltac:(match goal with H : preservation_ready_expr e |- _ => exact H end)
        Hfree_e Hlocal_e Hrefs) as [s1_with [Heval_e_with [Hrel1 [Hrefs1 Hv]]]].
      destruct (IHargs x T hidden s1_with Hrel1
        ltac:(match goal with H : preservation_ready_args es |- _ => exact H end)
        Hfree_es Hlocal_es Hrefs1) as [s2_with [Heval_args_with [Hrel2 [Hrefs2 Hvs]]]].
      exists s2_with. repeat split; try assumption.
      + eapply EvalArgs_Cons; eassumption.
      + constructor; assumption.
    - intros s x T hidden s_with Hrel _ _ _ Hrefs.
      exists s_with. repeat split; try constructor; assumption.
    - intros s s1 s2 fields f rest e v values Hlookup Heval_e IHe
        Heval_fields IHfields x T hidden s_with Hrel Hready Hfree Hlocal Hrefs.
      assert (Hready_e : preservation_ready_expr e)
        by (eapply preservation_ready_fields_lookup; eassumption).
      assert (Hfree_e : ~ In x (free_vars_expr e))
        by (eapply fields_free_vars_ts_lookup_notin; eassumption).
      assert (Hlocal_e : ~ In x (expr_local_store_names e))
        by (eapply fields_local_store_names_lookup_notin; eassumption).
      destruct (IHe x T hidden s_with Hrel Hready_e Hfree_e Hlocal_e Hrefs)
        as [s1_with [Heval_e_with [Hrel1 [Hrefs1 Hv]]]].
      destruct (IHfields x T hidden s1_with Hrel1 Hready Hfree Hlocal Hrefs1)
        as [s2_with [Heval_fields_with [Hrel2 [Hrefs2 Hvalues]]]].
      exists s2_with. repeat split; try assumption.
      + eapply EvalStructFields_Cons; eassumption.
      + constructor; assumption.
  }
  unfold consumed_hidden_frame_eval_lift_ready_mutual_rel.
  destruct Hmut as [Heval [Hargs Hfields]].
  repeat split.
  - intros x T hidden s_with s_base e s_base' result Hrel Hready Hfree
      Hlocal Hrefs Heval_base.
    destruct (Heval s_base e s_base' result Heval_base x T hidden s_with
      Hrel Hready Hfree Hlocal Hrefs) as [s_with' [Heval_with [Hrel' _]]].
    exists s_with'. split; assumption.
  - intros x T hidden s_with s_base args s_base' vs Hrel Hready Hfree
      Hlocal Hrefs Heval_base.
    destruct (Hargs s_base args s_base' vs Heval_base x T hidden s_with
      Hrel Hready Hfree Hlocal Hrefs) as [s_with' [Heval_with [Hrel' _]]].
    exists s_with'. split; assumption.
  - intros x T hidden s_with s_base fields defs s_base' values Hrel Hready
      Hfree Hlocal Hrefs Heval_base.
    destruct (Hfields s_base fields defs s_base' values Heval_base x T hidden
      s_with Hrel Hready Hfree Hlocal Hrefs) as [s_with' [Heval_with [Hrel' _]]].
    exists s_with'. split; assumption.
Qed.

